import { useEffect, useState } from "react";
import { useNavigate } from "react-router-dom";

const LOGO_URL = "https://media.base44.com/images/public/69cd2741578c9b5ce655395b/39a31f9b9_Untitleddesign3.png";
const HERO_LOGO_URL = "https://media.base44.com/images/public/69cd2741578c9b5ce655395b/d28cac677_Untitleddesign3.png"; "https://media.base44.com/images/public/69cd2741578c9b5ce655395b/39a31f9b9_Untitleddesign3.png";
const HTML_URL = "https://rawcdn.githack.com/chainwavestudios-cyber/agentbmaninvest/main/agentbman-pitchbook-v3.html";

export default function Home() {
  const [blobUrl, setBlobUrl] = useState(null);
  const navigate = useNavigate();

  useEffect(() => {
    fetch(HTML_URL)
      .then((r) => r.text())
      .then((html) => {
        let modified = html.replaceAll("AgentBman", "Rosie").replaceAll("agentbman", "rosie").replaceAll("50.5 GW", "50.5 GW → 330GW").replaceAll("Installed in 2023 alone · $200B+ US market", "2025 → 2032 · Global Market").replaceAll("Installed in 2025 alone · $200B+ US market", "2025 → 2032 · Global Market").replaceAll("2024 → 2032", "2026 → 2032").replaceAll("$62B", "$62B  →  $190B").replaceAll("Growing at 4.8% CAGR · Storm-driven demand", "2025 → 2032  · Storm-driven demand").replaceAll("15×\n\t\t\t\t\t\tCost Advantage on AI Voice vs. Industry", "").replaceAll("$0.01\n\t\t\t\t\t\tPer Minute — Full Stack AI Calls", "").replaceAll("20 min\n\t\t\t\t\t\tTo Start Dialing with AI Agents", "").replaceAll("$4.1B → $18B", "$4.1B → $40B").replaceAll("2024 → 2030", "2025 → 2032").replaceAll("28.3% CAGR", "38.46% CAGR").replaceAll("4.8% CAGR", "17.35% CAGR").replaceAll("22% CAGR", "30.82% CAGR").replaceAll("25.8% CAGR", "35.64% CAGR").replaceAll("$0.01/min all-in", "$0.01/min all-in (Rosie Cost)").replaceAll("Enrichment", "Enrichment (Custom API)\nWorkFlow Manager\nApify Web Scraping\nSMS Campaigns\n\nEnrichment");

        const injectedScript = `
<script>
(function() {
  const LOGO = "${LOGO_URL}";

  function applyChanges() {
    // Find the nav brand block: small container with "INVESTOR OVERVIEW" text inside nav
    const nav = document.querySelector('nav, header');
    if (!nav) return;

    const navEls = nav.querySelectorAll('*');
    for (const el of navEls) {
      const text = (el.textContent || '').trim();
      if (
        text.includes('INVESTOR OVERVIEW') &&
        text.length < 100 &&
        !el._rosieReplaced
      ) {
        el._rosieReplaced = true;
        el.innerHTML = '<img src="' + LOGO + '" style="height:55px;width:auto;object-fit:contain;display:block;" />';
        break;
      }
    }

    // Insert hero logo image below the main headline
    const allEls = document.querySelectorAll('*');
    for (const el of allEls) {
      const text = (el.textContent || '').toLowerCase();
      if (text.includes('ai engine') && text.includes('every lead')) {
        // Check if image already added to avoid duplicates
        if (el.nextElementSibling && el.nextElementSibling.tagName === 'IMG' && el.nextElementSibling.src.includes('d28cac677')) {
          return;
        }
        const img = document.createElement('img');
        img.src = HERO_LOGO_URL;
        img.style.cssText = 'display:block;margin:24px auto 0;width:180px;height:auto;';
        if (el.parentNode) {
          el.parentNode.insertBefore(img, el.nextSibling);
        }
        return;
      }
    }
  }

  if (document.readyState === 'loading') {
    document.addEventListener('DOMContentLoaded', applyChanges);
  } else {
    applyChanges();
  }
  setTimeout(applyChanges, 500);
  setTimeout(applyChanges, 1500);

  /* ── Team photos + To Be Hired ── */
  var ZHANG    = 'data:image/jpeg;base64,';
  var STEPHANI = 'data:image/jpeg;base64,';

  function makePhotoEl(src) {
    var wrap = document.createElement('div');
    wrap.style.cssText = 'width:70px;height:70px;border-radius:50%;overflow:hidden;margin:0 auto 10px;border:2px solid rgba(184,147,58,0.7)';
    var img = document.createElement('img');
    img.src = src;
    img.style.cssText = 'width:100%;height:100%;object-fit:cover;object-position:top center;display:block';
    wrap.appendChild(img);
    return wrap;
  }

  function getCard(el) {
    var p = el.parentElement;
    for (var i = 0; i < 8; i++) {
      if (!p) break;
      var st = p.getAttribute ? (p.getAttribute('style') || '') : '';
      if (st.indexOf('background') !== -1 || st.indexOf('border') !== -1 || st.indexOf('padding') !== -1) return p;
      p = p.parentElement;
    }
    return el.parentElement;
  }

  function findByExactText(text) {
    var all = document.querySelectorAll('h2,h3,h4,p,div,span');
    for (var i = 0; i < all.length; i++) {
      var el = all[i];
      if (el.children.length === 0 && (el.textContent || '').trim() === text) return el;
    }
    return null;
  }

  function hideSalary(card) {
    var els = card.querySelectorAll('*');
    for (var i = 0; i < els.length; i++) {
      var t = els[i].textContent || '';
      if (els[i].children.length === 0 && t.indexOf('/ month') !== -1 && t.indexOf('$') !== -1) {
        /* hide the salary pill and its parent container */
        els[i].style.display = 'none';
        if (els[i].parentElement) els[i].parentElement.style.display = 'none';
      }
    }
  }

  function findFirstIcon(card) {
    /* look for circular icon divs or existing imgs */
    var candidates = card.querySelectorAll('div,img');
    for (var i = 0; i < candidates.length; i++) {
      var st = (candidates[i].getAttribute ? candidates[i].getAttribute('style') : null) || '';
      if (st.indexOf('border-radius') !== -1 && (st.indexOf('50%') !== -1 || st.indexOf('50px') !== -1)) return candidates[i];
      if (candidates[i].tagName === 'IMG') return candidates[i];
    }
    return null;
  }

  function insertName(titleEl, name) {
    var el = document.createElement('div');
    el.textContent = name;
    el.style.cssText = 'font-weight:700;font-size:16px;color:#e8e0d0;text-align:center;margin-bottom:4px';
    titleEl.parentNode.insertBefore(el, titleEl);
  }

  function insertBadge(afterEl, text, color) {
    var b = document.createElement('div');
    b.textContent = text;
    b.style.cssText = 'text-align:center;font-size:10px;letter-spacing:1.5px;text-transform:uppercase;margin:3px 0 6px;color:' + color;
    afterEl.parentNode.insertBefore(b, afterEl.nextSibling);
  }

  function injectTeam() {

    /* Zhang Wei */
    var zEl = findByExactText('Chief Technology Engineer');
    if (zEl && !zEl._done) {
      zEl._done = true;
      var card = getCard(zEl);
      var icon = findFirstIcon(card);
      if (icon) { icon.parentNode.replaceChild(makePhotoEl(ZHANG), icon); }
      insertName(zEl, 'Zhang Wei');
      hideSalary(card);
    }

    /* Stephani Scheidt */
    var sEl = findByExactText('Director of Sales');
    if (sEl && !sEl._done) {
      sEl._done = true;
      var card2 = getCard(sEl);
      var icon2 = findFirstIcon(card2);
      if (icon2) { icon2.parentNode.replaceChild(makePhotoEl(STEPHANI), icon2); }
      insertName(sEl, 'Stephani Scheidt');
      insertBadge(sEl, 'Managing Partner', '#b8933a');
      hideSalary(card2);
    }

    /* 3 PH roles — To Be Hired */
    var phTitles = ['PH \u2014 Backend Engineer','PH \u2013 Backend Engineer',
                    'PH \u2014 Frontend Engineer','PH \u2013 Frontend Engineer',
                    'PH \u2014 Integrations Engineer','PH \u2013 Integrations Engineer'];
    var all2 = document.querySelectorAll('h2,h3,h4,p,div,span');
    for (var j = 0; j < all2.length; j++) {
      var el2 = all2[j];
      var t2 = (el2.textContent || '').trim();
      var isPH = el2.children.length === 0 && !el2._done &&
                 (phTitles.indexOf(t2) !== -1 ||
                  (t2.indexOf('PH') === 0 && (t2.indexOf('Backend') !== -1 || t2.indexOf('Frontend') !== -1 || t2.indexOf('Integrations') !== -1)));
      if (isPH) {
        el2._done = true;
        var badge2 = document.createElement('div');
        badge2.textContent = 'To Be Hired \u00b7 May 2026';
        badge2.style.cssText = 'text-align:center;background:rgba(96,165,250,0.12);color:#60a5fa;font-size:10px;padding:3px 10px;border-radius:3px;letter-spacing:1px;text-transform:uppercase;margin:5px auto 0;display:table';
        el2.parentNode.insertBefore(badge2, el2.nextSibling);
      }
    }
  }

  setTimeout(injectTeam, 900);
  setTimeout(injectTeam, 2000);
  setTimeout(injectTeam, 4000);

})();
</script>
`;

        modified = modified.replace("</body>", `${injectedScript}</body>`);

        const blob = new Blob([modified], { type: "text/html" });
        const url = URL.createObjectURL(blob);
        setBlobUrl(url);

        return () => URL.revokeObjectURL(url);
      });
  }, []);

  return (
    <div className="w-full h-screen" style={{ position: 'relative' }}>
      {blobUrl ? (
        <iframe src={blobUrl} className="w-full h-full border-0" title="Rosie Pitchbook" />
      ) : (
        <div className="w-full h-full flex items-center justify-center text-gray-500">Loading...</div>
      )}
      <button
        onClick={() => navigate('/portal-login')}
        style={{
          position: 'fixed', top: '16px', right: '20px',
          background: 'linear-gradient(135deg, #b8933a, #d4aa50)',
          color: '#0a0f1e', border: 'none', borderRadius: '2px',
          padding: '10px 22px', cursor: 'pointer',
          fontSize: '11px', fontWeight: '700', letterSpacing: '2px',
          textTransform: 'uppercase', fontFamily: 'Georgia, serif',
          zIndex: 9999, boxShadow: '0 4px 20px rgba(184,147,58,0.4)',
          display: 'flex', alignItems: 'center', gap: '8px',
        }}
      >
        🔐 Investor Data Portal
      </button>
    </div>
  );
}